function chunkArray(i,t=2){const a=[];for(let s=0;s<i.length;s+=t){const l=i.slice(s,s+t);a.push(l)}return a}function drawChunkedCertificates(i){let t="";return i.forEach(i=>{t+=`<div class="col-lg-6 certificates-text pl-3 pt-2">\n            <h6 class="mb-3 text-center">\n                <span class="text-muted">${i.dates}</span>\n                ${i.title}\n            </h6>\n            <div class="col-lg-12 img-certificates">\n                <a class="popup-link" href="${i.img}">\n                    <img class="img-fluid" title="ZOOM IMAGE" src="${i.imgCover}" alt="${i.title}">\n                </a>\n            </div>\n        </div>`}),t}function drawSiteUrl(i){return i.url?`URL: <a class="siteurl" target="_blank" href="${i.url}">${i.name}</a>`:'URL: <b class="text-danger">Page closed</b>'}function drawTechnologies(i){let t="";return i.split(",").forEach(i=>{t+=`<a href="#">${i}</a>`}),t}function drawData(i){siteData=i;for(const i in siteData.skills)skillsWrap.append(`\n            <div class="col-lg-3 col-md-4 col-sm-6 skills">\n                <span class="fa-5x">\n                    <img src="${siteData.skills[i].img}" alt="HTML">\n                </span>\n                <h4 class="skills-heading">${siteData.skills[i].title}</h4>\n            </div>\n        `);let t=chunkArray(Object.values(siteData.certificates));t.forEach(i=>{certificatesWrap.append(`<div class="col-lg-12 mt-3">\n            <div class="row">\n                ${drawChunkedCertificates(i)}\n            </div>\n        </div>`)});for(const i in siteData.portfolios)portfolioWrap.append(`\n            <div class="col-lg-4 col-md-6 col-sm-6 portfolio-item">\n                <div class="portfolio-link" data-key="${i}">\n                    <div class="portfolio-hover">\n                        <div class="portfolio-hover-content">\n                            <i class="fa fa-plus fa-3x"></i>\n                        </div>\n                    </div>\n                    <img class="img-fluid" src="${siteData.portfolios[i].coverImage}" alt="${siteData.portfolios[i].id}">\n                </div>\n                <div class="portfolio-caption">\n                    <h4>${siteData.portfolios[i].name}</h4>\n                    <p class="text-muted">${siteData.portfolios[i].type}</p>\n                </div>\n            </div>\n        `);$(".spinning-wrap").remove(),$(".popup-link").magnificPopup({type:"image",mainClass:"mfp-with-zoom",zoom:{enabled:!0,duration:300,easing:"ease-in-out",opener:function(i){return i.is("img")?i:i.find("img")}}})}let jsonApiUrl="../partials/api.json",siteData={},skillsWrap=$("#skills-wrapper"),certificatesWrap=$("#certificates-markup-wrap"),portfolioWrap=$("#portfolio-markup-wrap");axios.get(jsonApiUrl).then(i=>{drawData(i.data)}).catch(i=>{showToast("something wrong...","error")}),$(document).on("click",".portfolio-link",function(i){let t=$("#portfolio-modal"),a=$(this),s=siteData.portfolios[a.attr("data-key")];s&&(t.find("#portfolio-modal-content").html(`\n            <div class="col-lg-9 mx-auto">\n                <h2 class="text-uppercase">${s.title}</h2>\n                <ul class="list-inline">\n                    <li>RELEASE DATE: <b>${s.releaseDate}</b></li>\n                    <li>${drawSiteUrl(s)}</li>\n                </ul>\n                <div class="technologies col-lg-8 mx-auto">\n                    <h5 class="mt-2">Technologies used</h5>\n                    <div class="p-3">\n                        ${drawTechnologies(s.technologies)}\n                    </div>\n                </div>\n                <hr>\n                <p id="portfolio-description" class="p-3">${s.description}</p>\n                <div id="portfolion-content">\n                    <img class="img-fluid d-block mx-auto" src="${s.coverImage}" alt="">\n                    <hr>\n                    <br>\n                    <img class="img-fluid d-block mx-auto" src="${s.fullImage}" alt="">\n                </div>\n            </div>\n        `),setTimeout(()=>{t.modal()},100))});